import{_ as n}from"./plugin-vue_export-helper-DlAUqK2U.js";import{c as e,a,b as l,d as p,e as i,o as d}from"./app-4HWBeQql.js";const r={};function t(h,s){return d(),e("div",null,[s[0]||(s[0]=a("h1",{id:"前言",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#前言"},[a("span",null,"前言")])],-1)),s[1]||(s[1]=a("p",null,[i("学习尚硅谷的"),a("a",{href:"https://www.bilibili.com/video/BV1iq4y1u7vj",target:"_blank",rel:"noopener noreferrer"},"《MySQL数据库入门到大牛，mysql安装到优化》"),i("的分集104到114。")],-1)),l(" more "),s[2]||(s[2]=p(`<p>MySQL高级特性分为4个篇章：</p><ol><li>MySQL架构篇 <ul><li>第1章：MySQL的数据目录</li><li>第2章：用户与权限管理</li><li>第3章：逻辑架构</li><li>第4章：存储引擎</li></ul></li><li>索引及调优篇 <ul><li>第1章：索引</li><li>第2章：性能分析工具的使用</li><li>第3章：索引优化与SQL优化</li><li>第4章：数据库的设计规范</li><li>第5章：数据库其他调优策略</li></ul></li><li>事务篇 <ul><li>第1章：事务基础知识</li><li>第2章：MySQL事务日志</li><li>第3章：锁</li><li>第4章：多版本并发控制(MVCC)</li></ul></li><li>日志与备份篇 <ul><li>第1章：其它数据库日志</li><li>第2章：主从复制</li><li>第3章：数据库备份与恢复</li></ul></li></ol><h1 id="第1章-mysql的数据目录" tabindex="-1"><a class="header-anchor" href="#第1章-mysql的数据目录"><span>第1章：MySQL的数据目录</span></a></h1><p>我的MySQL数据库的安装目录：<code>/usr/local/mysql</code> 。</p><p>我的MySQL数据库的数据目录：<code>/usr/local/mysql/data</code> 。</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>mysql&gt; show variables like &#39;datadir&#39;;</span></span>
<span class="line"><span>+---------------+------------------------+</span></span>
<span class="line"><span>| Variable_name | Value                  |</span></span>
<span class="line"><span>+---------------+------------------------+</span></span>
<span class="line"><span>| datadir       | /usr/local/mysql/data/ |</span></span>
<span class="line"><span>+---------------+------------------------+</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>或者查看 <code>/etc/my.cnf</code> 配置文件内容：</p><div class="language-cnf line-numbers-mode" data-highlighter="shiki" data-ext="cnf" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-cnf"><span class="line"><span>[mysqld]</span></span>
<span class="line"><span>basedir=/usr/local/mysql</span></span>
<span class="line"><span>datadir=/usr/local/mysql/data</span></span>
<span class="line"><span>socket=/tmp/mysql.sock</span></span>
<span class="line"><span>user=mysql</span></span>
<span class="line"><span>secure_file_priv=/usr/local/mysql/mysql-files</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[client]</span></span>
<span class="line"><span>socket=/tmp/mysql.sock</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="系统表空间" tabindex="-1"><a class="header-anchor" href="#系统表空间"><span>系统表空间</span></a></h2><p>默认情况下，InnoDB会在数据目录下创建一个名为 <code>ibdata1</code> 、大小为 12M 的文件，这个文件就是对应的系统表空间（system tablespace）在文件系统上的表示。注意这个文件是自扩展文件，当不够用的时候它会自己增加文件大小。</p><p>如果你想让系统表空间对应文件系统上多个实际文件，或者仅仅觉得原来的 ibdata1 这个文件名难听，那可以在MySQL启动时配置对应的文件路径以及它们的大小，比如修改 my.cnf 配置文件：</p><div class="language-cnf line-numbers-mode" data-highlighter="shiki" data-ext="cnf" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-cnf"><span class="line"><span>[server]</span></span>
<span class="line"><span>innodb_data_file_path=data1:512M;data2:512M:autoextend</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="独立表空间" tabindex="-1"><a class="header-anchor" href="#独立表空间"><span>独立表空间</span></a></h2><p>在MySQL5.6.6以及之后的版本中，InnoDB并不会默认的把各个表的数据存储到系统表空间中，而是为每一个表建立一个独立表空间（file-per-table tablespace）。</p><p>存储表数据的话，会在该表所属数据库对应的子目录下创建一个表示该独立表空间的文件，文件名和表名相同，只不过添加了一个 <code>.ibd</code> 的扩展名。</p><p>比如：使用了独立表空间去存储 atguigu 数据库下的 test 表的话，那么在该表所在数据库对应的 atguigu 目录下会为 test 表创建这两个文件：</p><div class="language-txt line-numbers-mode" data-highlighter="shiki" data-ext="txt" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-txt"><span class="line"><span>test.frm</span></span>
<span class="line"><span>test.ibd</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>其中 <code>test.ibd</code> 文件就用来存储 test 表中的数据和索引，<br><code>test.frm</code> 用于描述表结构，该文件以二进制格式存储的。</p></blockquote><p>启动参数 <code>innodb_file_per_table</code> 可以指定使用系统表空间还是独立表空间来存储数据：</p><div class="language-cnf line-numbers-mode" data-highlighter="shiki" data-ext="cnf" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-cnf"><span class="line"><span>[server]</span></span>
<span class="line"><span>innodb_file_per_table=0 # 0：代表使用系统表空间； 1：代表使用独立表空间</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>默认情况下使用独立表空间存储。</p><div class="language-sql line-numbers-mode" data-highlighter="shiki" data-ext="sql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-sql"><span class="line"><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">mysql</span><span style="--shiki-light:#383A42;--shiki-dark:#56B6C2;">&gt;</span><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;"> show variables </span><span style="--shiki-light:#A626A4;--shiki-dark:#C678DD;">like</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> &#39;innodb_file_per_table&#39;</span><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">;</span></span>
<span class="line"><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">+</span><span style="--shiki-light:#A0A1A7;--shiki-light-font-style:italic;--shiki-dark:#7F848E;--shiki-dark-font-style:italic;">-----------------------+-------+</span></span>
<span class="line"><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">| Variable_name         | </span><span style="--shiki-light:#A626A4;--shiki-dark:#C678DD;">Value</span><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;"> |</span></span>
<span class="line"><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">+</span><span style="--shiki-light:#A0A1A7;--shiki-light-font-style:italic;--shiki-dark:#7F848E;--shiki-dark-font-style:italic;">-----------------------+-------+</span></span>
<span class="line"><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">| innodb_file_per_table | </span><span style="--shiki-light:#A626A4;--shiki-dark:#C678DD;">ON</span><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">    |</span></span>
<span class="line"><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">+</span><span style="--shiki-light:#A0A1A7;--shiki-light-font-style:italic;--shiki-dark:#7F848E;--shiki-dark-font-style:italic;">-----------------------+-------+</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="第2章-用户与权限管理" tabindex="-1"><a class="header-anchor" href="#第2章-用户与权限管理"><span>第2章：用户与权限管理</span></a></h1><h2 id="登录mysql服务器" tabindex="-1"><a class="header-anchor" href="#登录mysql服务器"><span>登录MySQL服务器</span></a></h2><p>启动MySQL服务后，可以通过mysql命令来登录MySQL服务器，命令如下：</p><div class="language-zsh line-numbers-mode" data-highlighter="shiki" data-ext="zsh" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-zsh"><span class="line"><span style="--shiki-light:#4078F2;--shiki-dark:#61AFEF;">mysql</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> –h</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> hostname</span><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">|</span><span style="--shiki-light:#4078F2;--shiki-dark:#61AFEF;">hostIP</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> –P</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> port</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> –u</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> username</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> –p</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> DatabaseName</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> –e</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> &quot;SQL语句&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#A0A1A7;--shiki-light-font-style:italic;--shiki-dark:#7F848E;--shiki-dark-font-style:italic;"># 举例</span></span>
<span class="line"><span style="--shiki-light:#4078F2;--shiki-dark:#61AFEF;">mysql</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> -uroot</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> -p</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> -hlocalhost</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> -P3306</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> mysql</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> -e</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> &quot;select host,user from user&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#A0A1A7;--shiki-light-font-style:italic;--shiki-dark:#7F848E;--shiki-dark-font-style:italic;"># 简略版</span></span>
<span class="line"><span style="--shiki-light:#4078F2;--shiki-dark:#61AFEF;">mysql</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> -u</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> root</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> -pabc123</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>-h</code> 指定主机名或者主机IP，hostname为主机，hostIP为主机IP。</li><li><code>-P</code> 指定MySQL服务的端口。MySQL服务的默认端口是3306，</li><li><code>-u</code> 指定接用户名</li><li><code>-p</code> 会提示输入密码。</li><li><code>DatabaseName</code> 指明登录到哪一个数据库中。如果没有该参数，就会直接登录到MySQL数据库中，然后可以使用USE命令来选择数据库。</li><li><code>-e</code> 后面可以直接加SQL语句。登录MySQL服务器以后即可执行这个SQL语句，然后退出MySQL服务器。</li></ul><h2 id="用户管理" tabindex="-1"><a class="header-anchor" href="#用户管理"><span>用户管理</span></a></h2><h3 id="创建用户" tabindex="-1"><a class="header-anchor" href="#创建用户"><span>创建用户</span></a></h3><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>-- CREATE USER语句</span></span>
<span class="line"><span>CREATE USER 用户名 [IDENTIFIED BY &#39;密码&#39;][,用户名 [IDENTIFIED BY &#39;密码&#39;]];</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>用户名参数由用户（User）和主机名（Host）构成；<br><code>CREATE USER</code> 语句可以同时创建多个用户。</p></blockquote><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>CREATE USER zhang3 IDENTIFIED BY &#39;123123&#39;; -- 默认host是 %</span></span>
<span class="line"><span>CREATE USER &#39;kangshifu&#39;@&#39;localhost&#39; IDENTIFIED BY &#39;123456&#39;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 查看当前有哪些用户</span></span>
<span class="line"><span>mysql&gt; SELECT user, host FROM mysql.user;</span></span>
<span class="line"><span>+------------------+-----------+</span></span>
<span class="line"><span>| user             | host      |</span></span>
<span class="line"><span>+------------------+-----------+</span></span>
<span class="line"><span>| zhang3           | %         |</span></span>
<span class="line"><span>| kangshifu        | localhost |</span></span>
<span class="line"><span>| mysql.infoschema | localhost |</span></span>
<span class="line"><span>| mysql.session    | localhost |</span></span>
<span class="line"><span>| mysql.sys        | localhost |</span></span>
<span class="line"><span>| root             | localhost |</span></span>
<span class="line"><span>+------------------+-----------+</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="修改用户" tabindex="-1"><a class="header-anchor" href="#修改用户"><span>修改用户</span></a></h3><p>修改用户名：</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>UPDATE mysql.user </span></span>
<span class="line"><span>SET USER=&#39;li4&#39; </span></span>
<span class="line"><span>WHERE USER=&#39;zhang3&#39;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>修改当前用户密码：使用 <code>ALTER USER</code> 命令。</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>ALTER USER USER() IDENTIFIED BY &#39;new_password&#39;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 示例</span></span>
<span class="line"><span>mysql -u zhang3 -p123123</span></span>
<span class="line"><span>ALTER USER USER() IDENTIFIED BY &#39;abc123&#39;;</span></span>
<span class="line"><span>mysql -u zhang3 -pabc123</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>修改其他用户密码：使用root用户登录MySQL后，可以使用SET语句来修改密码。</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>-- 方式一</span></span>
<span class="line"><span>ALTER USER user [IDENTIFIED BY &#39;new_password&#39;];</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 方式二</span></span>
<span class="line"><span>SET PASSWORD FOR &#39;username&#39;@&#39;hostname&#39;=&#39;new_password&#39;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 示例</span></span>
<span class="line"><span>SET PASSWORD FOR &#39;zhang3&#39;=&#39;123123&#39;;  -- 默认host是 %</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="删除用户" tabindex="-1"><a class="header-anchor" href="#删除用户"><span>删除用户</span></a></h3><p>使用 <code>DROP USER</code> 语句来删除用户时，必须用于DROP USER权限。DROP USER语句的基本语法形式如下：</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>DROP USER user[,user];</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 举例</span></span>
<span class="line"><span>DROP USER li4; -- 默认删除host为%的用户</span></span>
<span class="line"><span>DROP USER &#39;kangshifu&#39;@&#39;localhost&#39;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>DROP USER 命令会删除用户以及对应的权限。</p><h2 id="权限管理" tabindex="-1"><a class="header-anchor" href="#权限管理"><span>权限管理</span></a></h2><p>查看MySQL权限列表：</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>mysql&gt; show privileges;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>出于安全因素，授予权限的原则：</p><ol><li>只授予能满足需要的最小权限，防止用户干坏事。</li><li>创建用户的时候限制用户的登录主机，一般是限制成指定IP或者内网IP段。</li><li>为每个用户设置满足密码复杂度的密码 。</li><li>定期清理不需要的用户，回收权限或者删除用户。</li></ol><h3 id="查看权限" tabindex="-1"><a class="header-anchor" href="#查看权限"><span>查看权限</span></a></h3><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>-- 查看当前用户权限</span></span>
<span class="line"><span>SHOW GRANTS;</span></span>
<span class="line"><span>SHOW GRANTS FOR CURRENT_USER;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 查看其他用户</span></span>
<span class="line"><span>SHOW GRANTS FOR &#39;user&#39;@&#39;主机地址&#39; ;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="授予权限" tabindex="-1"><a class="header-anchor" href="#授予权限"><span>授予权限</span></a></h3><p>给用户授权的方式有2种：给用户赋予角色、直接给用户授权 。</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>GRANT 权限1,权限2,…权限n </span></span>
<span class="line"><span>ON 数据库名称.表名称 </span></span>
<span class="line"><span>TO 用户名@用户地址 </span></span>
<span class="line"><span>[IDENTIFIED BY ‘密码口令’];</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 举例</span></span>
<span class="line"><span>-- 给li4用户用本地命令行方式，授予atguigudb这个库下的所有表的插删改查的权限</span></span>
<span class="line"><span>GRANT SELECT,INSERT,DELETE,UPDATE </span></span>
<span class="line"><span>ON atguigudb.* </span></span>
<span class="line"><span>TO li4@localhost;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 授予通过网络方式登录的joe用户，对所有库所有表的全部权限，密码设为123。</span></span>
<span class="line"><span>-- 注意这里唯独不包括grant的权限</span></span>
<span class="line"><span>GRANT ALL PRIVILEGES </span></span>
<span class="line"><span>ON *.* </span></span>
<span class="line"><span>TO joe@&#39;%&#39; </span></span>
<span class="line"><span>IDENTIFIED BY &#39;123&#39;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="收回权限" tabindex="-1"><a class="header-anchor" href="#收回权限"><span>收回权限</span></a></h3><p>MySQL中使用<code>REVOKE</code>语句取消用户的权限。</p><p>使用REVOKE收回权限之后，用户账户的记录将从 db、host、tables_priv和columns_priv表中删除，但是用户账户记录仍然在 user 表中保存（删除user表中的账户记录使用<code>DROP USER</code>语句）。</p><blockquote><p>注意：在将用户账户从 user 表删除之前，应该收回相应用户的所有权限。<br> 注意：收回权限后，须用户重新登录后才能生效</p></blockquote><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>REVOKE 权限1,权限2,…权限n </span></span>
<span class="line"><span>ON 数据库名称.表名称 </span></span>
<span class="line"><span>FROM 用户名@用户地址;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="角色管理" tabindex="-1"><a class="header-anchor" href="#角色管理"><span>角色管理</span></a></h2><p>引入角色的目的是方便管理拥有相同权限的用户。</p><figure><img src="https://vip.123pan.cn/1844935313/obsidian/20260427095110018.png" alt="角色" width="600" tabindex="0" loading="lazy"><figcaption>角色</figcaption></figure><h3 id="创建角色" tabindex="-1"><a class="header-anchor" href="#创建角色"><span>创建角色</span></a></h3><p>创建角色使用 <code>CREATE ROLE</code> 语句，语法如下：</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>CREATE ROLE &#39;role_name&#39;[@&#39;host_name&#39;] [,&#39;role_name&#39;[@&#39;host_name&#39;]];</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 举例</span></span>
<span class="line"><span>CREATE ROLE &#39;manager&#39;@&#39;localhost&#39;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="授予权限-1" tabindex="-1"><a class="header-anchor" href="#授予权限-1"><span>授予权限</span></a></h3><p>创建角色之后，默认这个角色是没有任何权限的，我们需要给角色授权。</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>GRANT [privilege1,...] </span></span>
<span class="line"><span>ON table_name </span></span>
<span class="line"><span>TO &#39;role_name&#39;[@&#39;host_name&#39;];</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 举例</span></span>
<span class="line"><span>GRANT SELECT ON demo.settlement TO &#39;manager&#39;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="查看角色权限" tabindex="-1"><a class="header-anchor" href="#查看角色权限"><span>查看角色权限</span></a></h3><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>SHOW GRANTS FOR &#39;manager&#39;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="回收角色权限" tabindex="-1"><a class="header-anchor" href="#回收角色权限"><span>回收角色权限</span></a></h3><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>REVOKE privileges ON tablename FROM &#39;rolename&#39;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 举例</span></span>
<span class="line"><span>REVOKE INSERT, UPDATE, DELETE ON school.* FROM &#39;school_write&#39;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="删除角色" tabindex="-1"><a class="header-anchor" href="#删除角色"><span>删除角色</span></a></h3><p>当我们需要对业务重新整合的时候，可能就需要对之前创建的角色进行清理，删除一些不会再使用的角色。</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>DROP ROLE role [,role2...];</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="查看用户角色" tabindex="-1"><a class="header-anchor" href="#查看用户角色"><span>查看用户角色</span></a></h3><p>查看kangshifu用户的角色信息。</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>SHOW GRANTS FOR &#39;kangshifu&#39;@&#39;localhost&#39;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="赋予用户角色" tabindex="-1"><a class="header-anchor" href="#赋予用户角色"><span>赋予用户角色</span></a></h3><p>角色创建并授权后，要赋给用户并处于 激活状态 才能发挥作用。给用户添加角色可使用GRANT语句，语法形式如下：</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>GRANT role [,role2,...] </span></span>
<span class="line"><span>TO user [,user2,...];</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 举例</span></span>
<span class="line"><span>GRANT &#39;school_read&#39; TO &#39;kangshifu&#39;@&#39;localhost&#39;;</span></span>
<span class="line"><span>-- 添加完成后使用SHOW语句查看是否添加成功</span></span>
<span class="line"><span>SHOW GRANTS FOR &#39;kangshifu&#39;@&#39;localhost&#39;;</span></span>
<span class="line"><span>-- 使用kangshifu用户登录，然后查询当前角色，如果角色未激活，结果将显示NONE</span></span>
<span class="line"><span>SELECT CURRENT_ROLE();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="激活用户角色" tabindex="-1"><a class="header-anchor" href="#激活用户角色"><span>激活用户角色</span></a></h3><p>方式1：使用 set default role 命令激活角色。</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>SET DEFAULT ROLE ALL TO &#39;kangshifu&#39;@&#39;localhost&#39;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>方式2：将 activate_all_roles_on_login设置为ON。</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>-- 对所有角色永久激活。运行这条语句之后，用户才真正拥有了赋予角色的所有权限。</span></span>
<span class="line"><span>SET GLOBAL activate_all_roles_on_login=ON;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="撤销用户角色" tabindex="-1"><a class="header-anchor" href="#撤销用户角色"><span>撤销用户角色</span></a></h3><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>REVOKE role FROM user;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="第3章-逻辑架构" tabindex="-1"><a class="header-anchor" href="#第3章-逻辑架构"><span>第3章：逻辑架构</span></a></h1><figure><img src="https://vip.123pan.cn/1844935313/obsidian/20260427100946072.png" alt="mysql逻辑架构" width="500" tabindex="0" loading="lazy"><figcaption>mysql逻辑架构</figcaption></figure><p>MySQL架构图，简化为三层结构：</p><ol><li>连接层：客户端和服务器端建立连接，客户端发送 SQL 至服务器端；</li><li>SQL 层（服务层）：对 SQL 语句进行查询处理；与数据库文件的存储方式无关；</li><li>存储引擎层：与数据库文件打交道，负责数据的存储和读取。</li></ol><h2 id="连接层" tabindex="-1"><a class="header-anchor" href="#连接层"><span>连接层</span></a></h2><p>客户端访问 MySQL 服务器前，做的第一件事就是建立 TCP 连接。</p><p>经过三次握手建立连接成功后， MySQL 服务器对 TCP 传输过来的账号密码做身份认证、权限获取。</p><ul><li>用户名或密码不对，会收到一个Access denied for user错误，客户端程序结束执行</li><li>用户名密码认证通过，会从权限表查出账号拥有的权限与连接关联，之后的权限判断逻辑，都将依赖于此时读到的权限</li></ul><p>TCP 连接收到请求后，必须要分配给一个线程专门与这个客户端的交互。所以还会有个线程池，去走后面的流程。每一个连接从线程池中获取线程，省去了创建和销毁线程的开销。</p><h2 id="服务层" tabindex="-1"><a class="header-anchor" href="#服务层"><span>服务层</span></a></h2><h3 id="sql接口" tabindex="-1"><a class="header-anchor" href="#sql接口"><span>SQL接口</span></a></h3><p>接收用户的SQL命令，并且返回用户需要查询的结果。比如SELECT ... FROM就是调用SQL Interface</p><p>MySQL支持DML（数据操作语言）、DDL（数据定义语言）、存储过程、视图、触发器、自定义函数等多种SQL语言接口</p><h3 id="解析器" tabindex="-1"><a class="header-anchor" href="#解析器"><span>解析器</span></a></h3><p>在解析器（Parser）中对 SQL 语句进行语法分析、语义分析。将SQL语句分解成数据结构，并将这个结构传递到后续步骤，以后SQL语句的传递和处理就是基于这个结构的。如果在分解构成中遇到错误，那么就说明这个SQL语句是不合理的。</p><p>在SQL命令传递到解析器的时候会被解析器验证和解析（包括词法分析、语法分析），并为其创建<code>语法树</code>，并根据数据字典丰富查询语法树，会 验证该客户端是否具有执行该查询的权限 。创建好语法树后，MySQL还会对SQl查询进行语法上的优化，进行查询重写。</p><p>如果SQL语句正确，则会生成一个这样的语法树：</p><figure><img src="https://vip.123pan.cn/1844935313/obsidian/20260427102815708.png" alt="语法树" width="650" tabindex="0" loading="lazy"><figcaption>语法树</figcaption></figure><h3 id="优化器" tabindex="-1"><a class="header-anchor" href="#优化器"><span>优化器</span></a></h3><p>SQL语句在<strong>语法解析之后、查询之前</strong>会使用查询优化器（Optimizer）确定 SQL 语句的执行路径，生成一个执行计划 。</p><p>这个执行计划表明应该 使用哪些索引 进行查询（全表检索还是使用索引检索），表之间的连<br> 接顺序如何，最后会按照执行计划中的步骤调用存储引擎提供的方法来真正的执行查询，并将<br> 查询结果返回给用户。</p><p>在查询优化器中，可以分为逻辑查询优化阶段和物理查询优化阶段。</p><h3 id="查询缓存" tabindex="-1"><a class="header-anchor" href="#查询缓存"><span>查询缓存</span></a></h3><p>MySQL内部维持着一些Cache和Buffer，比如 Query Cache 用来缓存一条SELECT语句的执行结果，如果能够在其中找到对应的<strong>查询结果</strong>，那么就不必再进行查询解析、优化和执行的整个过程了，直接将结果反馈给客户端。</p><p>这个缓存机制是由一系列小缓存组成的。比如表缓存，记录缓存，key缓存，权限缓存等 。</p><h3 id="数据库缓冲区" tabindex="-1"><a class="header-anchor" href="#数据库缓冲区"><span>数据库缓冲区</span></a></h3><p>从MySQL 5.7.20开始，不推荐使用查询缓存，并在 MySQL 8.0中删除。<strong>数据库缓冲池</strong>（buffer pool）代替了查询缓存。</p><p>InnoDB 存储引擎是以页为单位来管理存储空间的，我们进行的增删改查操作其实本质上都是在访问页面（包括读页面、写页面、创建新页面等操作）。而磁盘 I/O 需要消耗的时间很多，而在内存中进行操作，效率则会高很多。</p><p>为了能让数据表或者索引中的数据随时被我们所用，DBMS 会申请占用内存来作为数据缓冲池，在真正访问页面之前，需要把在磁盘上的页缓存到内存中的缓冲池之后才可以访问。</p><p>查看 InnoDB 存储引擎的缓冲池的大小：</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>mysql&gt; show variables like &#39;innodb_buffer_pool_size&#39;;</span></span>
<span class="line"><span>+-------------------------+-----------+</span></span>
<span class="line"><span>| Variable_name           | Value     |</span></span>
<span class="line"><span>+-------------------------+-----------+</span></span>
<span class="line"><span>| innodb_buffer_pool_size | 134217728 |</span></span>
<span class="line"><span>+-------------------------+-----------+</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>修改缓冲池大小为256MB = 256x1024x1024B：</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>set global innodb_buffer_pool_size = 268435456;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 或者修改 /etc/my.cnf 配置文件</span></span>
<span class="line"><span>[server]</span></span>
<span class="line"><span>innodb_buffer_pool_size = 268435456</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>查看缓冲池的个数：</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>mysql&gt; show variables like &#39;innodb_buffer_pool_instances&#39;;</span></span>
<span class="line"><span>+------------------------------+-------+</span></span>
<span class="line"><span>| Variable_name                | Value |</span></span>
<span class="line"><span>+------------------------------+-------+</span></span>
<span class="line"><span>| innodb_buffer_pool_instances | 1     |</span></span>
<span class="line"><span>+------------------------------+-------+</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>创建两个缓冲区：</p><div class="language-cnf line-numbers-mode" data-highlighter="shiki" data-ext="cnf" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-cnf"><span class="line"><span>[server]</span></span>
<span class="line"><span>innodb_buffer_pool_instances = 2</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="引擎层" tabindex="-1"><a class="header-anchor" href="#引擎层"><span>引擎层</span></a></h2><p>插件式存储引擎层（ Storage Engines），真正的负责了MySQL中数据的存储和提取，对物理服务器级别维护的底层数据执行操作，服务器通过API与存储引擎进行通信。</p><p>不同的存储引擎具有的功能不同，这样我们可以根据自己的实际需要进行选取。</p><p>MySQL 8.0.45默认支持的存储引擎如下：</p><figure><img src="https://vip.123pan.cn/1844935313/obsidian/20260427102056170.png" alt="MySQL 8.0.45默认支持的存储引擎" tabindex="0" loading="lazy"><figcaption>MySQL 8.0.45默认支持的存储引擎</figcaption></figure><h2 id="存储层" tabindex="-1"><a class="header-anchor" href="#存储层"><span>存储层</span></a></h2><p>所有的数据，数据库、表的定义，表的每一行的内容，索引，都是存在文件系统上，以文件的方式存在的，并完成与存储引擎的交互。</p><p>当然有些存储引擎比如InnoDB，也支持不使用文件系统直接管理裸设备，但现代文件系统的实现使得这样做没有必要了。</p><h2 id="mysql查询流程" tabindex="-1"><a class="header-anchor" href="#mysql查询流程"><span>MySQL查询流程</span></a></h2><figure><img src="https://vip.123pan.cn/1844935313/obsidian/20260427102358378.png" alt="MySQL中的 SQL执行流程" tabindex="0" loading="lazy"><figcaption>MySQL中的 SQL执行流程</figcaption></figure><p>SQL 语句在 MySQL 中的流程是：SQL语句→查询缓存→解析器→优化器→执行器。</p><figure><img src="https://vip.123pan.cn/1844935313/obsidian/20260427103133088.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="使用profiling" tabindex="-1"><a class="header-anchor" href="#使用profiling"><span>使用profiling</span></a></h2><h3 id="确认profiling-是否开启" tabindex="-1"><a class="header-anchor" href="#确认profiling-是否开启"><span>确认profiling 是否开启</span></a></h3><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>select @@profiling;</span></span>
<span class="line"><span>-- 或</span></span>
<span class="line"><span>show variables like &#39;profiling&#39;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 开启profiling</span></span>
<span class="line"><span>set profiling=1;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="查看profiles" tabindex="-1"><a class="header-anchor" href="#查看profiles"><span>查看profiles</span></a></h3><p>查看当前会话所产生的所有 profiles：</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>show profiles; # 显示最近的几次查询</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>显示执行计划，查看程序的执行步骤：</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>-- 查看最近一条程序的执行步骤</span></span>
<span class="line"><span>show profile;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 查看指定 Query ID 的程序执行步骤</span></span>
<span class="line"><span>show profile for query 7;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="第4章-存储引擎" tabindex="-1"><a class="header-anchor" href="#第4章-存储引擎"><span>第4章：存储引擎</span></a></h1><p>MySQL 8.0.45默认支持的存储引擎如下：</p><figure><img src="https://vip.123pan.cn/1844935313/obsidian/20260427102056170.png" alt="MySQL 8.0.45默认支持的存储引擎" tabindex="0" loading="lazy"><figcaption>MySQL 8.0.45默认支持的存储引擎</figcaption></figure><h2 id="设置存储引擎" tabindex="-1"><a class="header-anchor" href="#设置存储引擎"><span>设置存储引擎</span></a></h2><h3 id="系统存储引擎" tabindex="-1"><a class="header-anchor" href="#系统存储引擎"><span>系统存储引擎</span></a></h3><p>查看系统默认的存储引擎：</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>mysql&gt; show variables like &#39;%storage_engine%&#39;;</span></span>
<span class="line"><span>+---------------------------------+-----------+</span></span>
<span class="line"><span>| Variable_name                   | Value     |</span></span>
<span class="line"><span>+---------------------------------+-----------+</span></span>
<span class="line"><span>| default_storage_engine          | InnoDB    |</span></span>
<span class="line"><span>| default_tmp_storage_engine      | InnoDB    |</span></span>
<span class="line"><span>| disabled_storage_engines        |           |</span></span>
<span class="line"><span>| internal_tmp_mem_storage_engine | TempTable |</span></span>
<span class="line"><span>+---------------------------------+-----------+</span></span>
<span class="line"><span></span></span>
<span class="line"><span>mysql&gt; SELECT @@default_storage_engine;</span></span>
<span class="line"><span>+--------------------------+</span></span>
<span class="line"><span>| @@default_storage_engine |</span></span>
<span class="line"><span>+--------------------------+</span></span>
<span class="line"><span>| InnoDB                   |</span></span>
<span class="line"><span>+--------------------------+</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>修改默认的存储引擎：</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>SET DEFAULT_STORAGE_ENGINE=MyISAM;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="表的存储引擎" tabindex="-1"><a class="header-anchor" href="#表的存储引擎"><span>表的存储引擎</span></a></h3><p>存储引擎是负责对表中的数据进行提取和写入工作的，我们可以为不同的表设置不同的存储引擎，也就是说不同的表可以有不同的物理存储结构，不同的提取和写入方式。</p><div class="language-mysql line-numbers-mode" data-highlighter="shiki" data-ext="mysql" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-mysql"><span class="line"><span>-- 创建表时指定存储引擎</span></span>
<span class="line"><span>CREATE TABLE 表名(</span></span>
<span class="line"><span>建表语句;</span></span>
<span class="line"><span>) </span></span>
<span class="line"><span>ENGINE = 存储引擎名称;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 修改表的存储引擎</span></span>
<span class="line"><span>ALTER TABLE 表名 </span></span>
<span class="line"><span>ENGINE = 存储引擎名称;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="存储引擎介绍" tabindex="-1"><a class="header-anchor" href="#存储引擎介绍"><span>存储引擎介绍</span></a></h2><table><thead><tr><th>对比项</th><th>MyISAM</th><th>InnoDB</th></tr></thead><tbody><tr><td>外键</td><td>不支持</td><td>支持</td></tr><tr><td>事务</td><td>不支持</td><td>支持</td></tr><tr><td>行表锁</td><td>表锁，即使操作一条记录也会锁住整个表，不适合高并发的操作</td><td>行锁，操作时只锁某一行，不对其它行有影响，适合高并发的操作</td></tr><tr><td>缓存</td><td>只缓存索引，不缓存真实数据</td><td>不仅缓存索引还要缓存真实数据，对内存要求高，而且内存大小对性能有决定性的影响</td></tr><tr><td>关注点</td><td>性能：节省资源、消耗少、简单业务</td><td>事务：并发写、事务、更大资源</td></tr><tr><td>默认安装</td><td>Y</td><td>N</td></tr><tr><td>默认使用</td><td>N</td><td>Y</td></tr></tbody></table><h3 id="innodb引擎" tabindex="-1"><a class="header-anchor" href="#innodb引擎"><span>InnoDB引擎</span></a></h3><p>InnoDB 引擎：具备外键支持功能的事务存储引擎。</p><p>InnoDB是MySQL的默认事务型引擎，它被设计用来处理大量的短期(short-lived)事务。可以确保事务的完整提交(Commit)和回滚(Rollback)。</p><p>对比MyISAM的存储引擎，InnoDB写的处理效率差一些，并且会占用更多的磁盘空间以保存数据和索引。</p><ul><li>MyISAM只缓存索引，不缓存真实数据；</li><li>InnoDB不仅缓存索引还要缓存真实数据，对内存要求较高，而且内存大小对性能有决定性的影响。</li></ul><blockquote><p>除了增加和查询外，还需要更新、删除操作，那么，应优先选择InnoDB存储引擎。</p></blockquote><h3 id="myisam引擎" tabindex="-1"><a class="header-anchor" href="#myisam引擎"><span>MyISAM引擎</span></a></h3><p>MyISAM 引擎：主要的非事务处理存储引擎。</p><p>MyISAM提供了大量的特性，包括全文索引、压缩、空间函数(GIS)等，但MyISAM 不支持事务、行级锁、外键 ，有一个毫无疑问的缺陷就是 崩溃后无法安全恢复 。</p><ul><li>优势是访问的速度快，对事务完整性没有要求或者以SELECT、INSERT为主的应用。</li><li>数据文件结构：表名.frm 存储表结构，表名.MYD 存储数据 (MYData)，表名.MYI 存储索引 (MYIndex)</li><li>应用场景：只读应用或者以读为主的业务</li></ul><h3 id="其他引擎" tabindex="-1"><a class="header-anchor" href="#其他引擎"><span>其他引擎</span></a></h3><p>Archive 引擎：用于数据存档。<br> Blackhole 引擎：丢弃写操作，读操作会返回空内容<br> CSV 引擎：存储数据时，以逗号分隔各个数据项<br> Memory 引擎：置于内存的表，缺点：其数据易丢失，生命周期短。<br> Federated 引擎：访问远程表<br> Merge引擎：管理多个MyISAM表构成的表集合<br> NDB引擎：MySQL集群专用存储引擎</p>`,170))])}const b=n(r,[["render",t]]),g=JSON.parse('{"path":"/database/MySQL%20%E9%AB%98%E7%BA%A7-%E6%9E%B6%E6%9E%84%E7%AF%87.html","title":"MySQL 高级-架构篇","lang":"zh-CN","frontmatter":{"title":"MySQL 高级-架构篇","date":"2026-04-28T00:00:00.000Z","tags":["MySQL"],"category":["数据库"],"description":"学习尚硅谷的《MySQL数据库入门到大牛，mysql安装到优化》的分集104到114。","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"MySQL 高级-架构篇\\",\\"image\\":[\\"https://vip.123pan.cn/1844935313/obsidian/20260427095110018.png\\",\\"https://vip.123pan.cn/1844935313/obsidian/20260427100946072.png\\",\\"https://vip.123pan.cn/1844935313/obsidian/20260427102815708.png\\",\\"https://vip.123pan.cn/1844935313/obsidian/20260427102056170.png\\",\\"https://vip.123pan.cn/1844935313/obsidian/20260427102358378.png\\",\\"https://vip.123pan.cn/1844935313/obsidian/20260427103133088.png\\",\\"https://vip.123pan.cn/1844935313/obsidian/20260427102056170.png\\"],\\"datePublished\\":\\"2026-04-28T00:00:00.000Z\\",\\"dateModified\\":\\"2026-04-28T02:12:47.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"庸碌无常\\",\\"url\\":\\"https://pluinyiasnhg.top\\"}]}"],["meta",{"property":"og:url","content":"https://pluinyiasnhg.top/database/MySQL%20%E9%AB%98%E7%BA%A7-%E6%9E%B6%E6%9E%84%E7%AF%87.html"}],["meta",{"property":"og:site_name","content":"庸碌无常的博客"}],["meta",{"property":"og:title","content":"MySQL 高级-架构篇"}],["meta",{"property":"og:description","content":"学习尚硅谷的《MySQL数据库入门到大牛，mysql安装到优化》的分集104到114。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://vip.123pan.cn/1844935313/obsidian/20260427095110018.png"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-04-28T02:12:47.000Z"}],["meta",{"property":"article:tag","content":"MySQL"}],["meta",{"property":"article:published_time","content":"2026-04-28T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2026-04-28T02:12:47.000Z"}]]},"git":{"createdTime":1777342367000,"updatedTime":1777342367000,"contributors":[{"name":"pluinyiasnhg","username":"pluinyiasnhg","email":"pluinyiasnhg@gmail.com","commits":1,"url":"https://github.com/pluinyiasnhg"}]},"readingTime":{"minutes":15.08,"words":4524},"filePathRelative":"database/MySQL 高级-架构篇.md","excerpt":"\\n<p>学习尚硅谷的<a href=\\"https://www.bilibili.com/video/BV1iq4y1u7vj\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">《MySQL数据库入门到大牛，mysql安装到优化》</a>的分集104到114。</p>\\n","autoDesc":true}');export{b as comp,g as data};
